 /*
+ * Get one character out of an iso filename
+ * Obey joliet_level
+ * Return number of bytes consumed
+ */
+int
+isochar(isofn, isoend, joliet_level, c)
+	u_char *isofn;
+	u_char *isoend;
+	int joliet_level;
+	u_char *c;
+{
+	*c = *isofn++;
+	if (joliet_level == 0 || isofn == isoend)
+		/* (00) and (01) are one byte in Joliet, too */
+		return 1;
+
+	/* No Unicode support yet :-( */
+	switch (*c) {
+	default:
+		*c = '?';
+		break;
+	case '\0':
+		*c = *isofn;
+		break;
+	}
+	return 2;
+}
