-				return 0;
-			case ';':
-				break;
-			}
-			for (i = 0; --fnlen >= 0; i = i * 10 + *fn++ - '0') {
-				if (*fn < '0' || *fn > '9') {
+		isofn += isochar(isofn, isoend, joliet_level, &c);
+		if (c == ';') {
+			if (*fn++ != ';')
+				return fn[-1];
+			for (i = 0; fn != fnend; i = i * 10 + *fn++ - '0')
+				if (*fn < '0' || *fn > '9')
 					return -1;
-				}
-			}
-			for (j = 0; --isolen >= 0; j = j * 10 + *isofn++ - '0');
